import 'package:uni_links/uni_links.dart';

Future<void> main() async {
  final handler = UniversalLinksHandler();
  await handler.init();
  handler.handleLink((link) async {
    if (link.pathSegments.isNotEmpty && link.pathSegments[0] == 'profile') {
      final id = link.pathSegments[1];
      // Navigate to profile page with user ID
      print('Navigating to profile page with ID: $id');
    } else if (link.pathSegments.isNotEmpty && link.pathSegments[0] == 'payment') {
      final paymentId = link.queryParameters['payment_id'];
      // Navigate to payment confirmation page with payment ID
      print('Navigating to payment confirmation page with payment ID: $paymentId');
    }
  });
}